@RestController
public class AuthorizationServer {

    @Autowired
    private ClientService clientService;

    @GetMapping("/oauth/authorize")
    public ResponseEntity<String> authorize(@RequestParam("client_id") String clientId,
                                           @RequestParam("redirect_uri") String redirectUri) {
        // Validate the client ID and redirect URI
        Client client = clientService.getClient(clientId);
        if (client == null || !redirectUri.startsWith(client.getBaseUrl())) {
            return ResponseEntity.badRequest().build();
        }

        // Generate an authorization code and store it in a HashMap with 10-minute expiration
        String authorizationCode = UUID.randomUUID().toString();
        HashMap<String, Long> authorizationCodes = new HashMap<>();
        authorizationCodes.put(authorizationCode, System.currentTimeMillis() + (10 * 60 * 1000));

        // Redirect the user to the redirect URI with the authorization code
        return ResponseEntity.status(HttpStatus.FOUND)
                .header("Location", redirectUri + "?code=" + authorizationCode)
                .build();
    }
}